// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract MembershipAirdrop {
    address private immutable _owner;
    mapping(address => uint256) public tierOf;
    mapping(address => bool) public claimed;
    mapping(address => uint256) public airdropCredits;
    mapping(address => uint256) public purchasedTokens;

    event TierSet(address indexed user, uint256 tier);
    event AirdropClaimed(address indexed user, uint256 credits);
    event TokensPurchased(address indexed user, uint256 amount);
    event Withdrawal(address indexed owner, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == _owner, "Not the owner");
        _;
    }

    constructor() {
        _owner = msg.sender;
    }

    function setTier(address user, uint256 tier) public onlyOwner {
        require(tier <= 10, "Tier exceeds maximum");
        tierOf[user] = tier;
        emit TierSet(user, tier);
    }

    function claimAirdrop() public {
        require(tierOf[msg.sender] > 0, "No tier assigned");
        require(!claimed[msg.sender], "Already claimed");
        uint256 credits = tierOf[msg.sender] * 100;
        airdropCredits[msg.sender] += credits;
        claimed[msg.sender] = true;
        emit AirdropClaimed(msg.sender, credits);
    }

    function purchaseTokens() public payable {
        require(msg.value > 0, "Value must be greater than 0");
        require(tierOf[msg.sender] > 0, "No tier assigned");
        uint256 tokenAmount = (msg.value * 1000) / 1 ether;
        purchasedTokens[msg.sender] += tokenAmount;
        emit TokensPurchased(msg.sender, tokenAmount);
    }

    function withdrawAll() public onlyOwner {
        uint256 balance = address(this).balance;
        payable(_owner).transfer(balance);
        emit Withdrawal(_owner, balance);
    }
}
